# app/health.py from fastapi import APIRouter, Response from datetime import datetime
router = APIRouter()
@router.get("/health") async def health(): """ Kubernetes readiness/liveness probe. CD pipeline checks this after deployment. """ return { "status": "healthy", "version": settings.APP_VERSION, "timestamp": datetime.utcnow().isoformat() }
@router.get("/health/ready") async def readiness(): """ Readiness probe: Can accept traffic? Checks all dependencies. """ checks = { "database": await check_database(), "redis": await check_redis(), "external_api": await check_external_api(), }
all_healthy = all(checks.values()) status_code = 200 if all_healthy else 503
return Response( content=json.dumps({"checks": checks, "ready": all_healthy}), status_code=status_code, media_type="application/json" )
